prompts.content:
{
  "design_system": {
    "metadata": {
      "style_name": "温馨故事书插画",
      "target_audience": "儿童/家庭",
      "reference_source": "上传图像",
      "version": "3.0"
    },
    "visual_parameters": {
      "medium": {
        "primary": "彩色铅笔",
        "secondary": "水彩晕染（仅变体）",
        "application": "手绘",
        "texture": {
          "type": "可见铅笔笔触",
          "quality": "略微粗糙的轮廓",
          "finish": "非写实/无照片纹理"
        }
      },
      "line_work": {
        "style": "清晰的线条艺术",
        "weight": "略带粗糙感/有机感",
        "clarity": "高"
      },
      "color_theory": {
        "base_tone": "温暖友好",
        "palette_type": "明亮柔和色调",
        "adjustments": {
          "brightness": "增加/高调",
          "saturation": "增强但自然",
          "contrast": "柔和"
        }
      },
      "lighting_and_shading": {
        "shadows": "最少",
        "highlights": "柔和",
        "rendering": "扁平但细节丰富",
        "gradients": "微妙的水彩层次（仅变体）"
      }
    },
    "subject_geometry": {
      "anatomy": {
        "proportions": "半卡通写实",
        "scale": "故事书风格"
      },
      "facial_features": {
        "eyes": "点状风格",
        "mouth": "小微笑",
        "complexity": "简约/极简"
      }
    },
    "atmosphere": {
      "mood": [
        "温馨",
        "愉悦",
        "温暖",
        "友好"
      ],
      "genre_tags": [
        "儿童读物",
        "生活素描",
        "故事书插画"
      ]
    }
  },
  "generation_configs": {
    "negative_prompt_tokens": [
      "写实",
      "照片级真实",
      "照片纹理",
      "暗色调",
      "复杂阴影",
      "3D渲染"
    ],
    "prompt_variations": [
      {
        "id": "PROMPT_001",
        "variant_name": "纹理彩色铅笔",
        "focus": "纹理与笔触",
        "full_text": "插画风格：手绘彩色铅笔插画，清晰的线条艺术配略带粗糙的铅笔轮廓，柔和的粉彩着色配增加的亮度，更轻盈鲜艳的色调，增强但自然的饱和度，可见的铅笔笔触和柔和的阴影纹理，温暖友好的基调，半卡通写实比例，简约的面部特征配点状眼睛和小微笑，扁平但细节丰富的着色，最少的阴影，柔和的高光，故事书插画感，温馨愉悦的氛围，明亮但柔和的色调，儿童读物/生活素描风格，高清晰度，无写实感，无照片纹理"
      },
      {
        "id": "PROMPT_002",
        "variant_name": "混合媒材水彩",
        "focus": "晕染与渐变",
        "full_text": "手绘彩色铅笔插画，清晰的线条艺术配略带粗糙的铅笔轮廓，结合柔和的水彩晕染纹理。明亮的粉彩色调，更轻盈鲜艳的色调配自然饱和度。可见的铅笔笔触与微妙的水彩渐变层次相叠。温暖友好的基调，半卡通写实比例。简约的面部特征配点状眼睛和小微笑。扁平但细节丰富的着色，最少的阴影，柔和的高光。故事书插画感，温馨愉悦的氛围，儿童读物风格，高清晰度，无写实感，无照片纹理。"
      }
    ]
  }
}

